165	async function expectAccessibleStructure(page: Page) {
166	  const audit = await page.evaluate(() => {
167	    const issues: string[] = [];
168	
169	    const getLabelText = (element: Element) => {
170	      const ariaLabel = element.getAttribute("aria-label")?.trim();
171	      if (ariaLabel) {
172	        return ariaLabel;
173	      }
174	
175	      const labelledBy = element.getAttribute("aria-labelledby");
176	      if (labelledBy) {
177	        const text = labelledBy
178	          .split(/\s+/)
179	          .map((id) => document.getElementById(id)?.textContent?.trim() ?? "")
180	          .join(" ")
181	          .trim();
182	
183	        if (text) {
184	          return text;
185	        }
186	      }
187	
188	      if (
189	        element instanceof HTMLInputElement ||
190	        element instanceof HTMLTextAreaElement ||
191	        element instanceof HTMLSelectElement
192	      ) {
193	        const label = element.labels?.[0]?.textContent?.trim();
194	
195	        if (label) {
196	          return label;
197	        }
198	      }
199	
200	      return element.textContent?.trim() ?? "";
201	    };
202	
203	    const interactive = document.querySelectorAll("a[href], button, input:not([type='hidden']), textarea, select");
204	
205	    interactive.forEach((element) => {
206	      if (!getLabelText(element)) {
207	        const id = element.id ? `#${element.id}` : "";
208	        issues.push(`unnamed:${element.tagName.toLowerCase()}${id}`);
209	      }
210	    });
211	
212	    document.querySelectorAll("nav").forEach((element, index) => {
213	      if (!element.getAttribute("aria-label")) {
214	        issues.push(`unlabeled-nav:${index + 1}`);
215	      }
216	    });
217	
218	    return {
219	      h1Count: document.querySelectorAll("h1").length,
220	      issues,
221	      lang: document.documentElement.lang,
222	      mainCount: document.querySelectorAll("main").length
223	    };
224	  });
225	
226	  expect(audit.lang).toBe("en");
227	  expect(audit.mainCount).toBe(1);
228	  expect(audit.h1Count).toBeGreaterThan(0);
229	  expect(audit.issues).toEqual([]);
230	}
